import{_ as i,c as a,o as s,a1 as e}from"./chunks/framework.DDNAyvCW.js";const u=JSON.parse('{"title":"Skills 故障排除与最佳实践","description":"","frontmatter":{},"headers":[],"relativePath":"docs/skills/troubleshooting/index.md","filePath":"docs/skills/troubleshooting/index.md"}'),t={name:"docs/skills/troubleshooting/index.md"};function o(r,l,n,h,c,d){return s(),a("div",null,l[0]||(l[0]=[e('<h1 id="skills-故障排除与最佳实践" tabindex="-1">Skills 故障排除与最佳实践 <a class="header-anchor" href="#skills-故障排除与最佳实践" aria-label="Permalink to &quot;Skills 故障排除与最佳实践&quot;">​</a></h1><p>本页介绍如何编写高质量的 Skills、优化性能以及避免常见问题。有关配置说明，请参阅 <a href="./../usage/">Skills 使用指南</a>。</p><h2 id="编写高质量的-skills" tabindex="-1">编写高质量的 Skills <a class="header-anchor" href="#编写高质量的-skills" aria-label="Permalink to &quot;编写高质量的 Skills&quot;">​</a></h2><h3 id="_1-清晰的命名和描述" tabindex="-1">1. 清晰的命名和描述 <a class="header-anchor" href="#_1-清晰的命名和描述" aria-label="Permalink to &quot;1. 清晰的命名和描述&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>AI 使用 Skill 的描述来决定何时应用它。模糊的描述会导致匹配遗漏或不准确。</p></div><ul><li><strong>编写具体的描述</strong>：明确说明 Skill 的用途和适用场景。包含重要关键词，并说明前置条件和预期结果。</li><li><strong>使用一致的命名</strong>：选择清晰、描述性的名称。可以添加分类前缀，如 <code>k8s-</code>、<code>docker-</code>、<code>git-</code>。在所有 Skills 中保持命名风格一致。</li></ul><h3 id="_2-结构化的步骤" tabindex="-1">2. 结构化的步骤 <a class="header-anchor" href="#_2-结构化的步骤" aria-label="Permalink to &quot;2. 结构化的步骤&quot;">​</a></h3><ul><li><p><strong>保持逻辑清晰</strong></p><ul><li>按执行顺序组织步骤。</li><li>使用编号列表明确顺序。</li><li>在行为分支处添加必要的判断和分支。</li></ul></li><li><p><strong>详细具体</strong></p><ul><li>包含完整的命令和参数。</li><li>说明每个步骤的意图。</li><li>在需要时提供示例和预期输出。</li></ul></li></ul><h3 id="_3-错误处理和回滚" tabindex="-1">3. 错误处理和回滚 <a class="header-anchor" href="#_3-错误处理和回滚" aria-label="Permalink to &quot;3. 错误处理和回滚&quot;">​</a></h3><ul><li><p><strong>处理失败情况</strong></p><ul><li>识别可能的错误条件。</li><li>为每个错误路径提供处理步骤。</li><li>说明如何判断操作是否成功。</li></ul></li><li><p><strong>定义回滚流程</strong></p><ul><li>对可能产生影响的操作，提供回滚步骤。</li><li>说明如何将系统恢复到操作前的状态。</li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>修改基础设施或数据的 Skills 应始终包含回滚部分。缺少回滚说明时，失败的操作可能导致系统处于不一致的状态。</p></div><h3 id="_4-可维护性" tabindex="-1">4. 可维护性 <a class="header-anchor" href="#_4-可维护性" aria-label="Permalink to &quot;4. 可维护性&quot;">​</a></h3><ul><li><p><strong>使用变量而非硬编码</strong></p><ul><li>尽量避免硬编码特定值。</li><li>使用占位符（如 <code>&lt;pod-name&gt;</code>、<code>&lt;namespace&gt;</code>）保持 Skill 的可复用性。</li><li>记录每个变量的含义和有效范围。</li></ul></li><li><p><strong>模块化设计</strong></p><ul><li>将复杂工作流拆分为更小、更专注的部分。</li><li>让每个步骤只负责一个关注点。</li><li>保持 Skills 易于测试和后续修改。</li></ul></li></ul><hr><h2 id="性能优化" tabindex="-1">性能优化 <a class="header-anchor" href="#性能优化" aria-label="Permalink to &quot;性能优化&quot;">​</a></h2><h3 id="控制启用的-skills-数量" tabindex="-1">控制启用的 Skills 数量 <a class="header-anchor" href="#控制启用的-skills-数量" aria-label="Permalink to &quot;控制启用的 Skills 数量&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">INFO</p><p>每个启用的 Skill 都会注入到 AI 系统提示中。启用过多的 Skills 会增加 token 用量，并可能分散 AI 的注意力。</p></div><ul><li><strong>只启用需要的</strong>：仅开启与当前任务相关的 Skills。定期清理不再使用的 Skills。</li><li><strong>按场景加载</strong>：根据当前任务切换不同的 Skill 集合。使用分组按场景管理 Skills，为不同工作流维护不同的集合。</li></ul><h3 id="优化-skill-内容" tabindex="-1">优化 Skill 内容 <a class="header-anchor" href="#优化-skill-内容" aria-label="Permalink to &quot;优化 Skill 内容&quot;">​</a></h3><ul><li><strong>精简步骤</strong>：移除不必要的步骤，合并可以安全并行执行的步骤，优化命令执行顺序以获得更快的反馈。</li><li><strong>降低复杂度</strong>：避免在单个 Skill 中使用过于复杂的条件逻辑。将非常复杂的 Skill 拆分为多个更简单的 Skills。将大量内容存储在资源文件中而非内联文本中。</li></ul><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><h3 id="terminal-skills-官方仓库" tabindex="-1">Terminal Skills 官方仓库 <a class="header-anchor" href="#terminal-skills-官方仓库" aria-label="Permalink to &quot;Terminal Skills 官方仓库&quot;">​</a></h3><ul><li><strong>GitHub</strong>：<a href="https://github.com/chaterm/terminal-skills" target="_blank" rel="noreferrer">chaterm/terminal-skills</a></li><li><strong>说明</strong>：专为终端工作流设计的精选 Skills 集合，涵盖各种运维和开发使用场景。</li></ul><hr><h2 id="后续阅读" tabindex="-1">后续阅读 <a class="header-anchor" href="#后续阅读" aria-label="Permalink to &quot;后续阅读&quot;">​</a></h2><ul><li>有关配置和使用说明，请参阅 <a href="./../usage/">Skills 使用指南</a>。</li><li>了解设置界面功能，请参考 <a href="/docs/settings/skills/">Skills 设置</a>。</li></ul>',27)]))}const g=i(t,[["render",o]]);export{u as __pageData,g as default};
